		function ClientSAVE()
{                    
  var GOOK = true;   

  //realiza validaciones para determinar si se puede o no avazar con el SAVE

  //si la liquidación está (A - Abierta) se permite editar el tipo de interfaz, pero manualmente NO se debe poder eletir el tipo (7- Interfaces AFIP) 
 	var bolEstCon = Ctrl('c_estado').GetXValue() == "A";

	if(Ctrl('main').GetMode() == "NEW" || bolEstCon)
	{       
			var tipoLiq = Ctrl('oi_tipo_liq').GetXValue(); 

			if (tipoLiq == "7")
			{   
				GOOK = false;
				alert('No es posible dar de alta en forma manual liquidaciones de tipo (7- Interfaces AFIP). Se debe utilizar la opción (Generar Interface LSD) desde una liquidación cerrada.');
			}

			var codigoLiq = Ctrl('c_liquidacion').GetXValue();

			var regex = new RegExp(/^[A-Za-z0-9_]+$/g);

			var resultado = regex.test(codigoLiq);

			if (resultado == false)
			{   
				GOOK = false;
				alert('En el campo "Codigo" solo se permiten letras, numeros y guion bajo.');
			}

	}

	if (GOOK)
	{
		Ctrl("main").DoEvent("SAVE");
	}



}

function Find()
{
	Ctrl("LIST").filter("",Ctrl("iter_search").GetCValue());
	validarLoad();
}

function cambiarRetro(pobjRetro) {
	CtrlEnabled('e_periodo_ret', (pobjRetro.GetCValue() == "1") );
	Ctrl('e_periodo_ret').SetCValue("");
}

function validarLoad() {

	//if (Ctrl('l_simulacion').GetCValue() == 1)
		//CtrlEnabled('CERRAR', false);

	var c_estado;
	if (Ctrl('LIST')) 
		c_estado = Ctrl('LIST').GetSelectAttrValue("c_estado");
	else 
		c_estado = Ctrl('c_estado').GetXValue();

	switch (c_estado)
	{
		case "C":
			CtrlEnabled('INICIALIZAR', false);
			CtrlEnabled('PROCESAR', false);
			CtrlEnabled('Editar', false);
			CtrlEnabled('CERRAR', false);
			CtrlEnabled('Borrar', false);  
			CtrlEnabled('VAL_VARGN_EDIT',false);
			CtrlEnabled('PERSONAS', true);  
			CtrlEnabled('GEN_INT',LiquidacionInterface());
			break;

		case "A":
			CtrlEnabled('INICIALIZAR', true);
			CtrlEnabled('PROCESAR', false);
			CtrlEnabled('Editar', true);
			CtrlEnabled('CERRAR', false);
			CtrlEnabled('Borrar', true);
			CtrlEnabled('VAL_VARGN_EDIT', true);
			CtrlEnabled('PERSONAS', false); 
			CtrlEnabled('GEN_INT',false);
			break;

		default:
			CtrlEnabled('INICIALIZAR', true);
			CtrlEnabled('PROCESAR', true);
			CtrlEnabled('CERRAR', true);
			CtrlEnabled('Editar', true);
			CtrlEnabled('Borrar', false);
			CtrlEnabled('VAL_VARGN_EDIT', true);
			CtrlEnabled('PERSONAS', true);  
			CtrlEnabled('GEN_INT',false);
			break;
	}

	if (Ctrl('main').GetMode() != "LIST")
	{
		var bolEstCon;

		bolEstCon = Ctrl('c_estado').GetXValue() == "A";

		//CtrlEnabled('f_liquidacion', bolEstCon);
		CtrlEnabled('oi_tipo_liq', bolEstCon);
		CtrlEnabled('c_clase', bolEstCon);
		//CtrlEnabled('e_quincena', bolEstCon);
		//CtrlEnabled('e_periodo', bolEstCon);
		//CtrlEnabled('f_pago', bolEstCon);
		//CtrlEnabled('l_retroactivo', bolEstCon);
		//CtrlEnabled('e_periodo_ret', bolEstCon); 
		quincenaValidar();      

	} 

}    

function LiquidacionInterface()
{     
	var valor;  
	var oi_liq_genero;
	if (Ctrl('LIST')) 
	{
		valor = Ctrl('LIST').GetSelectAttrValue("oi_tipo_liq");
		oi_liq_genero = Ctrl('LIST').GetSelectAttrValue("oi_liq_genero");
	}
	else
	{
		valor = Ctrl('oi_tipo_liq').GetXValue(); 
		oi_liq_genero = Ctrl('oi_liq_genero').GetXValue(); 
	}

	return (valor != "7" && valor != "6" && oi_liq_genero == "");
}                    



function cambiarPeriodo() { 


		var strFLiq = Ctrl('f_liquidacion').GetXValue();

		if (strFLiq != "")
			Ctrl('e_periodo').SetXValue(strFLiq.substr(0,6));


}

function cambiarClase() {
	if (Ctrl('c_clase').GetXValue() == "M")
	{
		CtrlEnabled('e_quincena', false);
		Ctrl('e_quincena').SetXValue('');
	}
	else
	{
		CtrlEnabled('e_quincena', true);
	}
}				

function fLiq_fPago(myThis) {
	if (Ctrl('f_liquidacion').GetCValue() != "") {

		if (Ctrl('f_pago').GetCValue() != "") {

			if (Ctrl('f_pago').GetXValue() < Ctrl('f_liquidacion').GetXValue()) {	

		  		myThis.SetError('La Fecha de Pago debe ser posterior o igual a la Fecha de Liquidacion.');
				return false;

			} else 
				return true;

		} else 
			return true;
	} else 
		return true;
}


function quincenaValidar(myThis) {

	if (Ctrl('c_clase').GetXValue() == "M") {
		Ctrl('e_quincena').SetXValue('');
		CtrlEnabled('e_quincena', false);
	}

	if (Ctrl('c_clase').GetXValue() == "Q") {

		if (Ctrl('e_quincena').GetXValue() == "") {
		  	myThis.SetError('Es necesario ingresar una quincena.');
			return false;

		} else
			return true;
	} else
		return true;
}	

function retroValidar(myThis) {
	if (Ctrl('l_retroactivo').GetCValue() == "1") {
		if (Ctrl('e_periodo_ret').GetCValue() == "") {
		  	myThis.SetError('Es necesario ingresar el Periodo Retroactivo.');
			return false;

		} else
			return true;

	} else
		return true;
}			

function validate () {
	return Ctrl('main').Validate();
}

function set_oi() {
	if (Ctrl('LIST'))
		Ctrl('oi').SetXValue(Ctrl('LIST').GetXValue());
	else
		Ctrl('oi').SetXValue(Ctrl('oi_ddo').GetXValue());	
}

function CALL_VAL_VARGN() {
	set_oi();
	Ctrl('main').DoEvent('CALL:VAL_VARGN');
}

function CALL_PERSONAS() {
	set_oi();
	openNewFlowWait("NucleusRH.Base.Liquidacion.Personal_Liquidacion.flow","initialize_liq","<DATA oi=\"" + Ctrl('oi').GetXValue() + "\" />",new ObjtectResult(),"L");
}

function refresh() {
	Ctrl('main').DoEvent('REFRESH');
}

