											{
											}
}

//Navegabilidad a Legajo Empresa
function verLegajo()
{     
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();
	var oisPersonalEmp="";
	var cantLegajos;  

	if(Ctrl("main").GetMode()=="LIST")        
		{
		var xmlLEGAJOS = nSQL.GetXML(Ctrl("main").getResource("QRY_LEGAJO"), "<PARAM oi_liquidacion=\""+Ctrl("LIST").GetSelectAttrValue("id")+"\" />");
		cantLegajos=Ctrl("LIST").GetSelectAttrValue("cant");
		} 
	else
		{
		var xmlLEGAJOS = nSQL.GetXML(Ctrl("main").getResource("QRY_LEGAJO"), "<PARAM oi_liquidacion=\""+Ctrl("oi_ddo").GetXValue()+"\" />"); 
		cantLegajos=Ctrl("cantidad").GetXValue();
		} 

    //Arma un string con el id de los Legajos que trajo el query
	for (legajo = xmlLEGAJOS.FirstChild(); legajo != null; legajo = legajo.Next()) 
		{
			if (legajo.Name == "LEGAJO") 
			{          
				if(oisPersonalEmp=="")
					oisPersonalEmp=legajo.GetAttr("id");
				else
					oisPersonalEmp=oisPersonalEmp+","+legajo.GetAttr("id");
			}
		}                 

	 if(cantLegajos!=0)
	 {
	 	//Pasa a Legajo Empresa con los Legajos Filtrados en oisPersonalEmp
		if(oisPersonalEmp!="")
			getFormInMain("NucleusRH.Base.Personal.LegajoEmpresa.flow", "ORGANIGRAMA",  "<LEGAJO VALUE=\""+oisPersonalEmp+"\" />", false);
		else
			alert("No tiene permisos de usuario para ver los Legajos de esta Liquidación");
	 }
	 else
	 	alert("No existen Legajos Empresa asignados a esta Liquidación"); 

}

//Navegabilidad a Legajo Liquidacion
function verLiquidacion()
{    
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();
	var oisPersonalEmp="";
	var cantLegajos; 

	if(Ctrl("main").GetMode()=="LIST")
		{ 
		var xmlLEGAJOS = nSQL.GetXML(Ctrl("main").getResource("QRY_LEGAJO"), "<PARAM oi_liquidacion=\""+Ctrl("LIST").GetSelectAttrValue("id")+"\" />"); 
		cantLegajos=Ctrl("LIST").GetSelectAttrValue("cant");
		}
	else 
		{
		var xmlLEGAJOS = nSQL.GetXML(Ctrl("main").getResource("QRY_LEGAJO"), "<PARAM oi_liquidacion=\""+Ctrl("oi_ddo").GetXValue()+"\" />"); 
		cantLegajos=Ctrl("cantidad").GetXValue();
		}                                       

	//Arma un string con el id de los Legajos que trajo el query
	for (legajo = xmlLEGAJOS.FirstChild(); legajo != null; legajo = legajo.Next()) 
		{
			if (legajo.Name == "LEGAJO") 
			{          
				if(oisPersonalEmp=="")
					oisPersonalEmp=legajo.GetAttr("id");
				else
					oisPersonalEmp=oisPersonalEmp+","+legajo.GetAttr("id");
			}
		} 

	if(cantLegajos!=0)
	 {
	 	//Pasa a Legajo Liquidación con los Legajos Filtrados en oisPersonalEmp
		if(oisPersonalEmp!="")
			getFormInMain("NucleusRH.Base.Liquidacion.Legajo.flow", "filterLegajos",  "<LEGAJO VALUE=\""+oisPersonalEmp+"\" />", false);
		else
			alert("No tiene permisos de usuario para ver los Legajos de esta Liquidación");
	 }
	 else
	 	alert("No existen Legajos Liquidación asignados a esta Liquidación");

}

//Navegabilidad a Empresa     
function verEmpresa()
{         
	if(Ctrl("main").GetMode()=="LIST")
		getFormInMain("NucleusRH.Base.Organizacion.Empresas.NAV.flow", "filter",  "<EMPRESA VALUE=\""+Ctrl("LIST").GetSelectAttrValue("oi_empresa")+"\" />", false);
	else
		getFormInMain("NucleusRH.Base.Organizacion.Empresas.NAV.flow", "filter",  "<EMPRESA VALUE=\""+Ctrl("oi_empresa").GetXValue()+"\" />", false);
}               


